execute_body:
# Top-down bond scout by category
bond_cat_node = args.get('slipnode')
if bond_cat_node is None:
    fizzle()

string = choose_string()
obj = choose_string_object(string, 'intra')
if obj is None:
    fizzle()

neighbor = choose_neighbor(obj)
if neighbor is None:
    fizzle()

# Try letter-category facet first
bond_facet = get_node('plato-letter-category')
obj_desc = None
neighbor_desc = None
for d in obj.descriptions:
    if d.description_type is bond_facet:
        obj_desc = d.descriptor
for d in neighbor.descriptions:
    if d.description_type is bond_facet:
        neighbor_desc = d.descriptor

if obj_desc is None or neighbor_desc is None:
    fizzle()

actual_cat = get_bond_category(obj_desc, neighbor_desc)
if actual_cat is not bond_cat_node:
    fizzle()

direction = None
sameness = get_node('plato-sameness')
if actual_cat is not sameness:
    if obj.left_string_pos < neighbor.left_string_pos:
        direction = get_node('plato-right')
    else:
        direction = get_node('plato-left')

propose_bond(obj, neighbor, actual_cat, bond_facet, obj_desc, neighbor_desc, direction)

# Top-down bond scout by direction
dir_node = args.get('slipnode')
if dir_node is None:
    fizzle()

string = choose_string()
obj = choose_string_object(string, 'intra')
if obj is None:
    fizzle()

# Pick neighbor in the specified direction
if dir_node.name == 'plato-left':
    if obj.left_string_pos == 0:
        fizzle()
    neighbor_obj = string.get_object_at(obj.left_string_pos - 1)
else:
    if obj.right_string_pos >= string.length - 1:
        fizzle()
    neighbor_obj = string.get_object_at(obj.right_string_pos + 1)

if neighbor_obj is None:
    fizzle()

bond_facet = get_node('plato-letter-category')
obj_desc = None
neighbor_desc = None
for d in obj.descriptions:
    if d.description_type is bond_facet:
        obj_desc = d.descriptor
for d in neighbor_obj.descriptions:
    if d.description_type is bond_facet:
        neighbor_desc = d.descriptor

if obj_desc is None or neighbor_desc is None:
    fizzle()

bond_cat = get_bond_category(obj_desc, neighbor_desc)
if bond_cat is None or bond_cat is get_node('plato-sameness'):
    fizzle()

propose_bond(obj, neighbor_obj, bond_cat, bond_facet, obj_desc, neighbor_desc, dir_node)

# Bond builder
bond = args.get('structure')
if bond is None:
    fizzle()

# Verify objects still exist in workspace
if bond.from_object.string is None or bond.to_object.string is None:
    fizzle()

build_structure(bond)

# Activate bond category and direction in slipnet
if bond.bond_category and bond.bond_category.name in slipnet.nodes:
    slipnet.nodes[bond.bond_category.name].activation = min(100, slipnet.nodes[bond.bond_category.name].activation + 50)
if bond.direction and bond.direction.name in slipnet.nodes:
    slipnet.nodes[bond.direction.name].activation = min(100, slipnet.nodes[bond.direction.name].activation + 50)

# Group builder
group = args.get('structure')
if group is None:
    fizzle()

# Verify constituent bonds still exist
for b in group.group_bonds:
    if not b.is_built:
        fizzle()

build_structure(group)

# Activate group category and direction
if group.group_category.name in slipnet.nodes:
    slipnet.nodes[group.group_category.name].activation = min(100, slipnet.nodes[group.group_category.name].activation + 50)
if group.direction and group.direction.name in slipnet.nodes:
    slipnet.nodes[group.direction.name].activation = min(100, slipnet.nodes[group.direction.name].activation + 50)

# Important-object bridge scout
from server.engine.bridges import Bridge, BRIDGE_TOP, BRIDGE_BOTTOM, BRIDGE_VERTICAL
from server.engine.concept_mappings import ConceptMapping

types_and_strings = [('top', BRIDGE_TOP, workspace.initial_string, workspace.modified_string)]
types_and_strings.append(('vertical', BRIDGE_VERTICAL, workspace.initial_string, workspace.target_string))
if justify_mode:
    types_and_strings.append(('bottom', BRIDGE_BOTTOM, workspace.target_string, workspace.answer_string))

weights = [max(0.1, 100 - mapping_strength(t[0])) for t in types_and_strings]
chosen = weighted_pick(types_and_strings, weights)
bt_name, bt, string1, string2 = chosen

if string2 is None:
    fizzle()

# Choose obj1 by relative importance
objects1 = string1.objects
if not objects1:
    fizzle()
import_weights = [max(0.1, o.relative_importance) for o in objects1]
obj1 = weighted_pick(objects1, import_weights)

# Pick a distinguishing description
relevant = [d for d in obj1.descriptions if d.is_relevant() and d.is_distinguishing()]
if not relevant:
    fizzle()
desc_weights = [max(0.1, d.descriptor.conceptual_depth) for d in relevant]
chosen_desc = weighted_pick(relevant, desc_weights)

# Search for obj2 with matching descriptor
_found = False
for obj2 in string2.objects:
    if _found:
        break
    for d2 in obj2.descriptions:
        if d2.description_type is chosen_desc.description_type and d2.descriptor is chosen_desc.descriptor:
            cms = []
            for dd1 in obj1.descriptions:
                for dd2 in obj2.descriptions:
                    if dd1.description_type is dd2.description_type:
                        label = None
                        if dd1.descriptor is dd2.descriptor:
                            label = get_node('plato-identity')
                        else:
                            for lk in dd1.descriptor.outgoing_links:
                                if lk.to_node is dd2.descriptor and lk.label_node:
                                    label = lk.label_node
                                    break
                        cms.append(ConceptMapping(dd1.description_type, dd1.descriptor, dd2.description_type, dd2.descriptor, label))
            if cms:
                bridge = Bridge(obj1, obj2, bt, cms)
                bridge.time_stamp = codelet_count
                avg_s = sum(cm.strength() for cm in cms) / len(cms)
                post_codelet('bridge-evaluator', round(avg_s), structure=bridge)
                _found = True
                break

if not _found:
    fizzle()

# Bridge builder
bridge = args.get('structure')
if bridge is None:
    fizzle()

# Verify both objects still exist
if bridge.object1.string is None or bridge.object2.string is None:
    fizzle()

build_structure(bridge)

# Activate concept-mapping descriptors
for cm in bridge.concept_mappings:
    for node_name in [cm.descriptor1.name, cm.descriptor2.name]:
        if node_name in slipnet.nodes:
            slipnet.nodes[node_name].activation = min(100, slipnet.nodes[node_name].activation + 30)

# Description evaluator
desc = args.get('structure')
if desc is None:
    fizzle()

# Activate the descriptor
if desc.descriptor.name in slipnet.nodes:
    slipnet.nodes[desc.descriptor.name].activation = min(100, slipnet.nodes[desc.descriptor.name].activation + 30)

if not evaluate_structure(desc):
    fizzle()

post_codelet('description-builder', round(desc.strength), structure=desc)

# Description builder
desc = args.get('structure')
if desc is None:
    fizzle()

if desc.object is None or desc.object.string is None:
    fizzle()

# Check not already present
for d in desc.object.descriptions:
    if d.description_type is desc.description_type and d.descriptor is desc.descriptor:
        fizzle()

build_structure(desc)

# Activate type and descriptor
for node_name in [desc.description_type.name, desc.descriptor.name]:
    if node_name in slipnet.nodes:
        slipnet.nodes[node_name].activation = min(100, slipnet.nodes[node_name].activation + 50)

# Answer justifier
from server.engine.answers import compute_answer_quality
from server.engine.trace import SNAG, ANSWER_FOUND

top_rules = workspace.get_supported_rules(True)
bottom_rules = workspace.get_supported_rules(False)

if not top_rules and not bottom_rules:
    fizzle()

# Try to find compatible rules
_justified = False
for tr in top_rules:
    if _justified:
        break
    for br in bottom_rules:
        if len(tr.clauses) == len(br.clauses):
            quality = compute_answer_quality(
                (tr.quality + br.quality) / 2, temperature.value, meta
            )
            record_event(ANSWER_FOUND, description=f'Justified with quality {quality}')
            _justified = True
            break

if not _justified:
    fizzle()

# Thematic bridge scout
from server.engine.bridges import Bridge, BRIDGE_TOP, BRIDGE_BOTTOM, BRIDGE_VERTICAL
from server.engine.concept_mappings import ConceptMapping

if not self_watching:
    fizzle()

# Find active bridge type with thematic pressure
pressure = None
for bt in ['top', 'vertical', 'bottom']:
    p = themespace.get_thematic_pressure(bt)
    if p:
        pressure = (bt, p)
        break

if pressure is None:
    fizzle()

bt_name, theme_pattern = pressure
bt_map = {'top': BRIDGE_TOP, 'bottom': BRIDGE_BOTTOM, 'vertical': BRIDGE_VERTICAL}
bt = bt_map[bt_name]

# Choose string pair
if bt == BRIDGE_TOP:
    s1, s2 = workspace.initial_string, workspace.modified_string
elif bt == BRIDGE_VERTICAL:
    s1, s2 = workspace.initial_string, workspace.target_string
else:
    s1, s2 = workspace.target_string, workspace.answer_string
    if s2 is None:
        fizzle()

key = 'horizontal_inter' if bt != BRIDGE_VERTICAL else 'vertical_inter'
obj1 = choose_string_object(s1, key)
obj2 = choose_string_object(s2, key)
if obj1 is None or obj2 is None:
    fizzle()

cms = []
for d1 in obj1.descriptions:
    for d2 in obj2.descriptions:
        if d1.description_type is d2.description_type:
            label = get_node('plato-identity') if d1.descriptor is d2.descriptor else None
            if label is None:
                for lk in d1.descriptor.outgoing_links:
                    if lk.to_node is d2.descriptor and lk.label_node:
                        label = lk.label_node
                        break
            cms.append(ConceptMapping(d1.description_type, d1.descriptor, d2.description_type, d2.descriptor, label))

if not cms:
    fizzle()

bridge = Bridge(obj1, obj2, bt, cms)
bridge.time_stamp = codelet_count
post_codelet('bridge-evaluator', round(themespace.get_max_positive_theme_activation()), structure=bridge)

# Progress watcher
from server.engine.jootsing import check_progress
from server.engine.commentary import emit_clamp_expired

if not self_watching:
    fizzle()

result = check_progress(workspace, trace, codelet_count, meta, commentary=commentary)

if result.action == 'undo_clamp':
    emit_clamp_expired(commentary, 'rule_codelet_clamp', 0.0, codelet_count)
    trace.within_clamp_period = False
    trace.last_unclamp_time = codelet_count
    coderack.unclamp_all()
    themespace.unclamp_all()
elif result.action == 'clamp_rule_pattern':
    pattern = meta.codelet_patterns.get('rule-codelet-pattern', [])
    if pattern:
        coderack.clamp_pattern(pattern)
        trace.record_clamp_start(codelet_count, temperature.value)
elif result.action == 'post_answer_finder':
    urgency = max(1, round(100 - temperature.value))
    if justify_mode:
        post_codelet('answer-justifier', urgency)
    else:
        post_codelet('answer-finder', urgency)
